import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{r as t,o as l,c as r,a as n,b as a,d as e,f as o}from"./app-a867567b.js";const p={},c=n("blockquote",null,[n("p",null,"今天记录一下MySQL 8.0 绿色版安装过程，简单粗暴。")],-1),m=n("h2",{id:"一、下载mysql",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#一、下载mysql","aria-hidden":"true"},"#"),a(" 一、下载MySQL")],-1),g={href:"https://dev.mysql.com/",target:"_blank",rel:"noopener noreferrer"},d=n("li",null,[n("p",null,"软件路径：DOWNLOAD–>MYSQL Community Downloads–>MYSQL on Windows")],-1),u=o('<img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308152917146.png" alt="image-20230308152917146" style="zoom:80%;"><h2 id="二、解压" tabindex="-1"><a class="header-anchor" href="#二、解压" aria-hidden="true">#</a> 二、解压</h2><p><strong>解压zip压缩包至想要安装的目录，比如解压到 D:\\mysql-8.0.32-winx64</strong></p><figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308153548884.png" alt="image-20230308153548884" tabindex="0" loading="lazy"><figcaption>image-20230308153548884</figcaption></figure><h2 id="三、配置my-ini文件" tabindex="-1"><a class="header-anchor" href="#三、配置my-ini文件" aria-hidden="true">#</a> 三、配置my.ini文件</h2>',5),h=n("strong",null,"在解压目录",-1),y={href:"https://so.csdn.net/so/search?q=MySQL%E9%85%8D%E7%BD%AE%E6%96%87%E4%BB%B6&spm=1001.2101.3001.7020",target:"_blank",rel:"noopener noreferrer"},k=n("strong",null,"my.ini",-1),b=o(`<figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308153653898.png" alt="image-20230308153653898" tabindex="0" loading="lazy"><figcaption>image-20230308153653898</figcaption></figure><p>配置文件<strong>my.ini</strong>内容如下</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token punctuation">[</span>mysqld<span class="token punctuation">]</span>
<span class="token comment"># 设置3306端口</span>
port<span class="token operator">=</span><span class="token number">3306</span>
<span class="token comment"># 设置mysql的安装目录</span>
basedir<span class="token operator">=</span>D:\\Program Files\\<span class="token keyword">DataBase</span>\\MySql\\mysql8<span class="token punctuation">.</span><span class="token number">0</span>  
<span class="token comment"># 设置mysql数据库的数据的存放目录</span>
datadir<span class="token operator">=</span>D:\\Program Files\\<span class="token keyword">DataBase</span>\\MySql\\mysql8<span class="token punctuation">.</span><span class="token number">0</span>\\<span class="token keyword">Data</span>  
<span class="token comment"># 允许最大连接数</span>
max_connections<span class="token operator">=</span><span class="token number">200</span>
<span class="token comment"># 允许连接失败的次数。这是为了防止有人从该主机试图攻击数据库系统</span>
max_connect_errors<span class="token operator">=</span><span class="token number">10</span>
<span class="token comment"># 服务端使用的字符集默认为UTF8</span>
<span class="token keyword">character</span><span class="token operator">-</span><span class="token keyword">set</span><span class="token operator">-</span>server<span class="token operator">=</span>utf8
<span class="token comment"># 创建新表时将使用的默认存储引擎</span>
<span class="token keyword">default</span><span class="token operator">-</span>storage<span class="token operator">-</span><span class="token keyword">engine</span><span class="token operator">=</span><span class="token keyword">INNODB</span>
<span class="token comment"># 默认使用“mysql_native_password”插件认证</span>
default_authentication_plugin<span class="token operator">=</span>mysql_native_password
<span class="token punctuation">[</span>mysql<span class="token punctuation">]</span>
<span class="token comment"># 设置mysql客户端默认字符集</span>
<span class="token keyword">default</span><span class="token operator">-</span><span class="token keyword">character</span><span class="token operator">-</span><span class="token keyword">set</span><span class="token operator">=</span>utf8mb4
<span class="token punctuation">[</span>client<span class="token punctuation">]</span>
<span class="token comment"># 设置mysql客户端连接服务端时默认使用的端口</span>
port<span class="token operator">=</span><span class="token number">3306</span>
<span class="token keyword">default</span><span class="token operator">-</span><span class="token keyword">character</span><span class="token operator">-</span><span class="token keyword">set</span><span class="token operator">=</span>utf8
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="四、运行准备" tabindex="-1"><a class="header-anchor" href="#四、运行准备" aria-hidden="true">#</a> 四、运行准备</h2><p><strong>以管理员身份打开命令行，切换到安装MySQL的目录下，再切换到bin目录下</strong></p><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308154130024.png" alt="image-20230308154130024" style="zoom:80%;"><p><strong>然后切换到mysql的bin目录下</strong></p><figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308163450092.png" alt="image-20230308163450092" tabindex="0" loading="lazy"><figcaption>image-20230308163450092</figcaption></figure><h2 id="五、安装" tabindex="-1"><a class="header-anchor" href="#五、安装" aria-hidden="true">#</a> 五、安装</h2><p><strong>执行MySQL初始化命令 mysqld --initialize --console</strong></p><figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308163623315.png" alt="image-20230308163623315" tabindex="0" loading="lazy"><figcaption>image-20230308163623315</figcaption></figure><p><strong>初始化完成后生成的用户名和密码（红框所示位置即为密码），即root用户和生成的密码，后续我们可以更改。</strong></p><p><strong>安装MySQL的服务mysqld，同样在bin目录下，执行MySQL服务安装命令 mysqld --install 服务名(不写的话默认服务名是mysql)</strong></p><figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308163714601.png" alt="image-20230308163714601" tabindex="0" loading="lazy"><figcaption>image-20230308163714601</figcaption></figure><p><code>因为我这里先前已经安装了，这里只是展示一下</code>。</p><p>启动MySQL服务，命令为：net start mysql80。其中(停止服务：net stop mysql80 ，卸载服务：sc delete 服务名)</p><figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308163746873.png" alt="image-20230308163746873" tabindex="0" loading="lazy"><figcaption>image-20230308163746873</figcaption></figure><h2 id="六、登录mysql" tabindex="-1"><a class="header-anchor" href="#六、登录mysql" aria-hidden="true">#</a> 六、登录MySQL</h2><p><strong>输入命令：mysql -u root -p ，（其中-u root表示用户名为root，-p表示登录密码）登录，然后提示输入密码，密位为先前初始化红框所示。</strong></p><figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308163817166.png" alt="image-20230308163817166" tabindex="0" loading="lazy"><figcaption>image-20230308163817166</figcaption></figure><p><strong>由于自动生成的密码比较复杂，我们可以更改密码，更改密码命令为：alter user root@’localhost’ identified by ‘xsq!@123’; 其中单引号内为更改后的密码。</strong></p><figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308163834647.png" alt="image-20230308163834647" tabindex="0" loading="lazy"><figcaption>image-20230308163834647</figcaption></figure><p><strong>然后输入exit;命令退出mysql，重新登录mysql检验一下密码是否修改成功，</strong></p><figure><img src="https://gaoziman.oss-cn-hangzhou.aliyuncs.com/blog/image-20230308164103186.png" alt="image-20230308164103186" tabindex="0" loading="lazy"><figcaption>image-20230308164103186</figcaption></figure>`,24);function f(v,_){const s=t("ExternalLinkIcon");return l(),r("div",null,[c,m,n("ol",null,[n("li",null,[n("p",null,[a("进入官网找到自己所需的安装包："),n("a",g,[a("MySQL :: Developer Zone"),e(s)]),a("，")])]),d]),u,n("p",null,[h,a("D:\\mysql-8.0.29-winx64中创建"),n("a",y,[a("MySQL配置文件"),e(s)]),k]),b])}const x=i(p,[["render",f],["__file","install-mysql8-green-version.html.vue"]]);export{x as default};
